function getHighestSale(card) {
  if (!card.rarity || card.rarity === "C") return "<0.5 ETH";
  if (card.rarity === "R") return "0.5–2 ETH";
  const wKey = `${card.collection?.toLowerCase()}:${card.token_id}`;
  const p = PRICE_MAP[wKey];
  if (!p) return card.rarity === "LR" ? "≥10 ETH" : "2–10 ETH";
  return p >= 1 ? `${p % 1 === 0 ? p : parseFloat(p.toFixed(3))} ETH` : `${parseFloat(p.toFixed(3))} ETH`;
}

